private void crossTabDataCell2_BeforePrint(object sender, DevExpress.XtraReports.UI.CrossTab.CrossTabCellPrintEventArgs e) {
     XRCrossTabCell cell = (XRCrossTabCell)sender;
       // Get values from the data source
    decimal settedEggs = cell.GetCurrentFieldValue<decimal>("SettedEggs");
    decimal chicks = cell.GetCurrentFieldValue<decimal>("Chicks");

    // Apply calculation
    decimal result = (settedEggs != 0) ? ((chicks / settedEggs) * 100) : 0;

    // Display result formatted as percentage (two decimals)
    cell.Text = result.ToString("0.00") ;

  }

private void crossTabTotalCell31_BeforePrint(object sender, DevExpress.XtraReports.UI.CrossTab.CrossTabCellPrintEventArgs e) {
       XRCrossTabCell cell = (XRCrossTabCell)sender;

// Safe conversion using Convert.ToDecimal instead of casting directly
    decimal totalEggs = Convert.ToDecimal(cell.GetCurrentFieldValue("TotalEggs"));
    decimal settedEggs = Convert.ToDecimal(cell.GetCurrentFieldValue("SettedEggs"));

    // Percentage calculation
    decimal result = (totalEggs != 0) ? (settedEggs / totalEggs) * 100 : 0;

    // Assign formatted text to cell
    cell.Text = result.ToString("0.00") ;

}


private void crossTabTotalCell5_BeforePrint(object sender, DevExpress.XtraReports.UI.CrossTab.CrossTabCellPrintEventArgs e) {
    XRCrossTabCell cell = (XRCrossTabCell)sender;

    decimal value = 0;
    try { value = cell.GetCurrentFieldValue<decimal>("SettedEggs"); } catch {}

    totalSettedEggs += value;  // accumulate total
}

private void crossTabTotalCell10_BeforePrint(object sender, DevExpress.XtraReports.UI.CrossTab.CrossTabCellPrintEventArgs e) {
    XRCrossTabCell cell = (XRCrossTabCell)sender;
    decimal totalSettedEggsChicksPerc = 0;
    decimal valuOfSettedEggs = 0;
    decimal totalChicksPerc = 0;
    decimal valuOfChicks = 0;

    try { valuOfSettedEggs = cell.GetCurrentFieldValue<decimal>("SettedEggs"); } catch {}
    try { valuOfChicks = cell.GetCurrentFieldValue<decimal>("Chicks"); } catch {}
    totalSettedEggsChicksPerc += valuOfSettedEggs ;  // accumulate total
    totalChicksPerc += valuOfChicks ;
    decimal weightedAvg = (totalSettedEggsChicksPerc != 0)
                            ? (totalChicksPerc / totalSettedEggsChicksPerc ) * 100 
                            : 0;

    cell.Text = weightedAvg.ToString("0.00") ;
}

