private void xrTableCell7_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
     XRTableCell cell = sender as XRTableCell;

    decimal valuOfSettedEggs = 0;
    decimal totalSettedEggsChicksPerc = 0;

    // Read field value safely
    if (GetCurrentColumnValue("SettedEggs") != null)
    {
        try
        {
            valuOfSettedEggs = Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));
        }
        catch { }
    }

    // accumulate
    totalSettedEggsChicksPerc += valuOfSettedEggs;
    decimal TotalSettedEggs = totalSettedEggsChicksPerc;

    // assign result to cell
    cell.Text = TotalSettedEggs.ToString("N0");   // formatted with no decimals
    }

